(async () => {
      try {
        let questionnaireAttachment = null;
        if (application) {
          if (
            ![
              CollectionNames.APSandDocumentTranslations,
              CollectionNames.Ausbildungs,
            ].includes(collectionName)
          ) {
            const questionnaireCollection = new ModelService(
              this.dataServices,
              applyToQuestionnaireCollections[collectionName],
              this.user,
            );

            if (!questionnaireCollection.model)
              return {
                statusCode: 404,
                message: 'Invalid Model',
              };
            const questionnaireSchema =
              await questionnaireCollection.getSchema();
            if (application?.questionnaireId) {
              const questionnaires = await questionnaireCollection.get({
                _id: application?.questionnaireId,
              });

              questionnaireAttachment =
                await this.modelHelper.generateQuestionnairePDFandStoreUserDocs(
                  applyToQuestionnaireCollections[collectionName],
                  questionnaireSchema,
                  questionnaires,
                  item,
                  application,
                  this.user?.type == UserTypes.AGENT ||
                    this.user?.type == UserTypes.ORG_AGENT
                    ? applicationUser
                    : this.user,
                  this.dataServices,
                  collectionName,
                  this.user,
                );
            }
          } else {
            questionnaireAttachment =
              await this.modelHelper.generateQuestionnairePDFandStoreUserDocs(
                applyToQuestionnaireCollections[collectionName],
                {},
                {},
                item,
                application,
                this.user?.type == UserTypes.AGENT ||
                  this.user?.type == UserTypes.ORG_AGENT
                  ? applicationUser
                  : this.user,
                this.dataServices,
                collectionName,
                this.user,
              );
          }
        } else {
          throw new AppException(
            'Failed to generate application form',
            HttpStatus.BAD_REQUEST,
          );
        }

        if (item.state === ApplicationStates.PUBLISHED) {
          const sendMail = this.modelHelper.sendUserApplicationMail(
            userDetails,
            userOrgDetails,
            service,
            item.isAgent,
            authUser,
            isCourse,
            collectionName,
            referredUser,
            referredUserOrgDetails,
            item?.application_uid,
            application?.id,
            questionnaireAttachment,
          );
          if (!sendMail) {
            throw new AppException(
              'Failed to send email ',
              HttpStatus.BAD_REQUEST,
            );
          }

          if (item && item?.application_uid) {
            const emailMessage = `Your Unique Application ID: ${item?.application_uid}<br/>
Please keep this ID safe — you will need it for future reference.`;
            const subject = `Your Unique Application ID - ${startCase(
              collectionName,
            )} - ${service?.name}`;
            this.modelHelper.sendUserCommonEmail(
              userDetails,
              authUser,
              subject,
              emailMessage,
            );
          }
          if (
            [
              UserTypes.SUPER_ADMIN,
              UserTypes.STAFF,
              UserTypes.TEAM_LEAD,
              UserTypes.MANAGER,
              UserTypes.AGENT,
              UserTypes.ORG_AGENT,
              UserTypes.ORG_OWNER,
              UserTypes.ORG_ADMIN,
            ].includes(referredUser?.type)
          ) {
            const sendReferralMail =
              this.modelHelper.sendReferralApplicationMail(
                userDetails,
                userOrgDetails,
                item.isAgent,
                authUser,
                referredUser,
                referredUserOrgDetails,
                application?.id,
                this.dataServices,
              );

            if (!sendReferralMail) {
              throw new AppException(
                'Failed to send referral confirmation mail ',
                HttpStatus.BAD_REQUEST,
              );
            }
          }
        }
      } catch (err) {
        console.error(
          'Generate application form and send email is failed:',
          err,
        );
      }
    })
